// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/ai_coach_report_controller.dart';
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/utils/environment.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_subscription.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/usage_limit_alert_snack_bar.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/ai_coach_report_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/recording_fab.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/resource_list_tab.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/session_meta_data_menu_anchor.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/session_scatter_chart.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/session_tab_bar.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_session_refresh.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// A page widget class to display data of a session.
/// It shows the list of the resources (i.e., videos and their analysis results) associated to the session.
/// By tapping an analyzed resource item, its `ResourceDetailsPage` will open.
/// Uploading local videos and re-analyzing failed videos also will be managed by this widget.
class SessionDetailsPage extends HookConsumerWidget {
  const SessionDetailsPage({
    required this.session,
    required this.teamId,
    required this.sessionId,
    super.key,
  });

  final String teamId;
  final String sessionId;
  final Session session;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final handleAccessDenied = useAccessDeniedNavigation();
    final currentSession = useState<Session>(session);
    // TODO: Remove this condition
    //
    // _SessionDetailsPageContent 内で tabController を定義すると
    // refresh 時に tab が最初に戻ってしまうためここで定義
    final tabController = useTabController(initialLength: isDevOrTest ? 3 : 2);
    final resourceState = ref.watch(
      resourceDataListControllerProvider(
        teamId: teamId,
        sessionId: sessionId,
      ),
    );

    return resourceState.when(
      data: (resourceData) => _SessionDetailsPageContent(
        resourcePagingData: resourceData,
        currentSession: currentSession,
        teamId: teamId,
        tabController: tabController,
        onSessionUpdated: (updatedSession) {
          currentSession.value = updatedSession;
        },
      ),
      loading: () => Scaffold(
        appBar: CustomAppBar(isBackNavigation: true),
        body: const CustomLoadingIndicator(),
      ),
      error: (error, stackTrace) {
        if (error is ForbiddenFailure) {
          handleAccessDenied();
          return const SizedBox.shrink();
        }

        return Scaffold(
          appBar: CustomAppBar(isBackNavigation: true),
          floatingActionButton: FloatingActionButton(
            backgroundColor: context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
            onPressed: null,
            child: const Icon(Icons.videocam_outlined),
          ),
          body: Center(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                IconButton(
                  onPressed: () {
                    ref
                      ..invalidate(resourceDataListControllerProvider(
                        teamId: teamId,
                        sessionId: sessionId,
                      ))
                      ..invalidate(teamListControllerProvider);
                  },
                  icon: const Icon(Icons.refresh),
                ),
                Text(context.l10n.get_data_failed),
                const Gap(8),
                Text(
                  (error is Failure)
                      ? error.translate(context.l10n)
                      : error.toString(),
                  textAlign: TextAlign.center,
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

class _SessionDetailsPageContent extends HookConsumerWidget {
  const _SessionDetailsPageContent({
    required this.resourcePagingData,
    required this.currentSession,
    required this.teamId,
    required this.tabController,
    required this.onSessionUpdated,
  });

  final PagingData<ResourceData> resourcePagingData;
  final ValueNotifier<Session> currentSession;
  final String teamId;
  final TabController tabController;
  final void Function(Session) onSessionUpdated;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final userId = ref.watch(profileStorageProvider).getUserId();
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final (canSubscribe, subscriptionStatus, restrictionMessage) =
        useSubscription();

    final onRefresh = useSessionRefresh(currentSession: currentSession);

    final reportState = ref.watch(
      aICoachReportControllerProvider(
        teamId: teamId,
        reportId: currentSession.value.aiCoachReport?.id,
      ),
    );

    return Scaffold(
      appBar: AppBar(
        leading: IconButton(
          tooltip: "Back",
          icon: Icon(
            isIos ? Icons.arrow_back_ios_new : Icons.arrow_back,
            size: 20,
          ),
          onPressed: () {
            Navigator.of(context).pop(true);
          },
        ),
        title: SessionMetaDataMenuAnchor(session: currentSession.value),
        actions: [
          if (!currentSession.value
              .isEditableByUser(userId, accessibleContents))
            const SizedBox.shrink()
          else
            IconButton(
              onPressed: () async {
                final result = await Navigator.of(context).pushNamed(
                  HomeRouter.editSessionPage,
                  arguments: {'session': currentSession.value},
                );
                if (result is Session) {
                  currentSession.value = result;
                  onSessionUpdated(result);
                }
              },
              icon: const Icon(Icons.settings),
            ),
        ],
        bottom: PreferredSize(
          preferredSize: const Size.fromHeight(24),
          child: Padding(
            padding: HomePage.bodyPadding,
            child: SessionTabBar(controller: tabController),
          ),
        ),
      ),
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding.copyWith(top: 8),
          child: Stack(
            children: [
              TabBarView(
                controller: tabController,
                children: [
                  ResourceListTab(
                    resourcePagingData: resourcePagingData,
                    session: currentSession.value,
                    onRefresh: onRefresh,
                  ),
                  SessionScatterChart(
                    teamId: teamId,
                    sessionId: currentSession.value.id!,
                  ),
                  // TODO: Remove this condition
                  if (isDevOrTest)
                    RefreshIndicator(
                      onRefresh: () async {
                        await onRefresh();
                        // タブを AI レポートに移動する
                        WidgetsBinding.instance.addPostFrameCallback((_) {
                          tabController.animateTo(2);
                        });
                      },
                      child: AICoachReportContainer(
                        player: currentSession.value.player,
                        currentSession: currentSession,
                        reportState: reportState,
                      ),
                    ),
                ],
              ),
              Align(
                alignment: Alignment.bottomCenter,
                child: Padding(
                  padding: context.isPortrait
                      ? const EdgeInsets.only(right: 66, bottom: 10)
                      : const EdgeInsets.only(right: 66, bottom: 32),
                  child: const UsageLimitAlertSnackBar(),
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: ListenableBuilder(
        listenable: tabController,
        builder: (context, child) {
          if (tabController.index == 0) {
            return RecordingFab(
              currentSession: currentSession.value,
              teamId: teamId,
              canSubscribe: canSubscribe,
            );
          }
          return const SizedBox.shrink();
        },
      ),
    );
  }
}

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/action_plans_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/count_strategy_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/empty_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/lefty_strategy_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/new_pitch_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pitch_features_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pitch_zones_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pros_cons_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/regenerate_report_content.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/report_generation_status_content.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/strikeout_strategy_expansion_tile.dart';

class AICoachReportContainer extends HookConsumerWidget {
  const AICoachReportContainer({
    required this.currentSession,
    required this.reportState,
    required this.player,
    super.key,
  });

  final ValueNotifier<Session> currentSession;
  final AsyncValue<AICoachReport?> reportState;
  final Player? player;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final handleAccessDenied = useAccessDeniedNavigation();

    return reportState.when(
      loading: () => const SizedBox.shrink(),
      error: (error, stackTrace) {
        if (error is ForbiddenFailure) {
          handleAccessDenied();
          return const SizedBox.shrink();
        }

        return ReportGenerationStatusContent(
          currentSession: currentSession,
          player: player,
          title: context.l10n.ai_coach_report__generation_failed_title,
          description:
              context.l10n.ai_coach_report__generation_failed_description,
          buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
        );
      },
      data: (report) {
        if (report == null) {
          return EmptyContainer(player: player, currentSession: currentSession);
        }

        final generationState = report.status;

        if (generationState == AICoachReportStatus.failed) {
          return ReportGenerationStatusContent(
            player: player,
            title: context.l10n.ai_coach_report__generation_failed_title,
            description:
                context.l10n.ai_coach_report__generation_failed_description,
            buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
            currentSession: currentSession,
          );
        }

        if (generationState == AICoachReportStatus.cancelled) {
          return ReportGenerationStatusContent(
            player: player,
            title: context.l10n.ai_coach_report__generation_canceled_title,
            description:
                context.l10n.ai_coach_report__generation_canceled_description,
            buttonLabel:
                context.l10n.ai_coach_report__generation_restart_button,
            currentSession: currentSession,
          );
        }

        if (generationState == AICoachReportStatus.accepted) {
          return const _ReportGenerationProcessingView();
        }

        if (generationState == AICoachReportStatus.completed &&
            report.content == null) {
          return ReportGenerationStatusContent(
            player: player,
            title: context.l10n.ai_coach_report__generation_failed_title,
            description:
                context.l10n.ai_coach_report__generation_failed_description,
            buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
            currentSession: currentSession,
          );
        }

        final content = report.content!;

        return SingleChildScrollView(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              if (content.pitchFeatures != null) ...[
                PitchFeaturesExpansionTile(
                  pitchFeatures: content.pitchFeatures!,
                  params: report.params,
                ),
                const Gap(8),
              ],
              if (content.prosCons != null) ...[
                ProsConsExpansionTile(prosCons: content.prosCons!),
                const Gap(8),
              ],
              if (content.countRecommendations != null) ...[
                CountStrategyExpansionTile(
                  entries: content.countRecommendations!,
                ),
                const Gap(8),
              ],
              if (content.strikeoutStrategies != null) ...[
                StrikeoutStrategyExpansionTile(
                  strategies: content.strikeoutStrategies!,
                ),
                const Gap(8),
              ],
              if (content.leftyStrategies != null) ...[
                LeftyStrategyExpansionTile(
                  strategies: content.leftyStrategies!,
                ),
                const Gap(8),
              ],
              if (content.pitchZones != null) ...[
                PitchZonesExpansionTile(items: content.pitchZones!),
                const Gap(8),
              ],
              if (content.newPitches != null) ...[
                NewPitchExpansionTile(
                  proposals: content.newPitches!,
                  params: report.params,
                ),
                const Gap(8),
              ],
              if (content.actionPlans != null) ...[
                ActionPlansExpansionTile(items: content.actionPlans!),
                const Gap(8),
              ],
              const Gap(24),
              RegenerateReportContent(
                player: player,
                currentSession: currentSession,
              ),
              const Gap(24),
            ],
          ),
        );
      },
    );
  }
}

class _ReportGenerationProcessingView extends StatelessWidget {
  const _ReportGenerationProcessingView();

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;

    return LayoutBuilder(
      builder: (context, constraints) {
        return SingleChildScrollView(
          physics: const AlwaysScrollableScrollPhysics(),
          child: ConstrainedBox(
            constraints: BoxConstraints(minHeight: constraints.maxHeight),
            child: Center(
              child: Padding(
                padding: const EdgeInsets.all(24),
                child: ConstrainedBox(
                  constraints: const BoxConstraints(maxWidth: 360),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(
                        Icons.autorenew_rounded,
                        size: 36,
                        color: colorScheme.primary,
                      ),
                      const Gap(16),
                      Text(
                        context.l10n.ai_coach_report__processing_title,
                        style: theme.textTheme.titleMedium?.copyWith(
                          fontWeight: FontWeight.w600,
                          color: colorScheme.onSurface,
                        ),
                        textAlign: TextAlign.center,
                      ),
                      const Gap(8),
                      Text(
                        context.l10n.ai_coach_report__processing_description,
                        style: theme.textTheme.bodyMedium?.copyWith(
                          color: colorScheme.onSurfaceVariant,
                        ),
                        textAlign: TextAlign.center,
                      ),
                    ],
                  ),
                ),
              ),
            ),
          ),
        );
      },
    );
  }
}

