### 案2: **SessionDetailsController を作る（最も明確）** ⭐⭐

3つの状態を1つのコントローラーで管理します。

```dart
// lib/controllers/session_details_controller.dart
@freezed
class SessionDetailsState with _$SessionDetailsState {
  const factory SessionDetailsState({
    required Session session,
    required PagingData<ResourceData> resources,
    AICoachReport? report,
  }) = _SessionDetailsState;
}

@riverpod
class SessionDetailsController extends _$SessionDetailsController {
  @override
  Future<SessionDetailsState> build({
    required String teamId,
    required String sessionId,
  }) async {
    // 並列でフェッチ
    final results = await Future.wait([
      _fetchSession(),
      _fetchResources(),
    ]);

    final session = results[0] as Session;
    final resources = results[1] as PagingData<ResourceData>;

    // レポートは session に reportId がある場合のみフェッチ
    AICoachReport? report;
    if (session.aiCoachReport?.id != null) {
      report = await _fetchReport(session.aiCoachReport!.id);
    }

    return SessionDetailsState(
      session: session,
      resources: resources,
      report: report,
    );
  }

  Future<Session> _fetchSession() async {
    final result = await ref.read(repositoryProvider).getSession(
      teamId: teamId,
      sessionId: sessionId,
    );

    if (result.hasLeft) throw result.left;
    return result.right;
  }

  Future<PagingData<ResourceData>> _fetchResources() async {
    // resourceDataListController のロジックを呼ぶ
    return await ref.read(
      resourceDataListControllerProvider(
        teamId: teamId,
        sessionId: sessionId,
      ).future,
    );
  }

  Future<AICoachReport?> _fetchReport(String reportId) async {
    try {
      return await ref.read(
        aICoachReportControllerProvider(
          teamId: teamId,
          reportId: reportId,
        ).future,
      );
    } catch (e) {
      return null;
    }
  }

  Future<void> refresh() async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() async {
      final results = await Future.wait([
        _fetchSession(),
        _fetchResources(),
      ]);

      final session = results[0] as Session;
      final resources = results[1] as PagingData<ResourceData>;

      AICoachReport? report;
      if (session.aiCoachReport?.id != null) {
        report = await _fetchReport(session.aiCoachReport!.id);
      }

      return SessionDetailsState(
        session: session,
        resources: resources,
        report: report,
      );
    });
  }

  Future<void> generateReport() async {
    final currentState = state.value;
    if (currentState == null) return;

    // レポート生成 API を呼ぶ
    await ref.read(repositoryProvider).createAIReport(
      teamId: teamId,
      sessionId: sessionId,
    );

    // 再フェッチ
    await refresh();
  }
}
