@riverpod
String? sessionReportId({
  required String teamId,
  required String sessionId,
}) {
  // sessionListController から session を取得して reportId を返す
  final sessionList = ref.watch(sessionListControllerProvider);

  return sessionList.whenOrNull(
    data: (teams) {
      final team = teams.firstWhereOrNull((t) => t.id == teamId);
      final session = team?.sessions?.firstWhereOrNull((s) => s.id == sessionId);
      return session?.aiCoachReport?.id;
    },
  );
}
