part 'session_details_state.freezed.dart';

/// SessionDetailsPage で必要な全ての状態を集約
@freezed
class SessionDetailsState with _$SessionDetailsState {
  const SessionDetailsState._();

  const factory SessionDetailsState({
    /// セッション情報（必須）
    required Session session,

    /// リソースリスト（必須）
    required PagingData<ResourceData> resources,

    /// AI コーチレポート（オプショナル）
    /// session.aiCoachReport?.id が null の場合は null
    /// 取得失敗時も null
    AICoachReport? report,

    /// レポート取得失敗時のエラー（オプショナル）
    /// report が null で、かつ session に reportId がある場合に設定
    @Default(null) String? reportError,
  }) = _SessionDetailsState;

  /// レポートが存在するかどうか
  bool get hasReport => session.aiCoachReport?.id != null;

  /// レポートが読み込み中かどうか
  bool get isReportLoading => 
      hasReport && report == null && reportError == null;

  /// レポートが生成済みで表示可能かどうか
  bool get canShowReport => 
      report != null && 
      report!.status == AICoachReportStatus.completed &&
      report!.content != null;
}
