### 3. コントローラーの実装

```dart
// lib/controllers/session_details_controller.dart
/// {@category Controllers}
library;

import 'package:fimber/fimber.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

import 'package:baseball_detector_flutter/controllers/check_result.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/models/session_details_state.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'session_details_controller.g.dart';

@riverpod
class SessionDetailsController extends _$SessionDetailsController {
  static final _logger = FimberLog('SessionDetailsController');

  @override
  Future<SessionDetailsState> build({
    required String teamId,
    required String sessionId,
  }) async {
    return await _fetchAllData();
  }

  /// 全てのデータを並列で取得
  Future<SessionDetailsState> _fetchAllData() async {
    _logger.d('Fetching all data for session: $sessionId');

    try {
      // 並列で Session と Resources を取得（高速化）
      final results = await Future.wait([
        _fetchSession(),
        _fetchResources(),
      ]);

      final session = results[0] as Session;
      final resources = results[1] as PagingData<ResourceData>;

      // Session に reportId がある場合のみレポートを取得
      AICoachReport? report;
      String? reportError;

      final reportId = session.aiCoachReport?.id;
      if (reportId != null) {
        try {
          report = await _fetchReport(reportId);
        } catch (e, stackTrace) {
          _logger.w('Failed to fetch report', ex: e, stacktrace: stackTrace);
          reportError = e.toString();
        }
      }

      return SessionDetailsState(
        session: session,
        resources: resources,
        report: report,
        reportError: reportError,
      );
    } catch (e, stackTrace) {
      _logger.e('Failed to fetch session details', 
          ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  /// セッション情報を取得
  Future<Session> _fetchSession() async {
    final result = await ref.read(repositoryProvider).getSession(
      teamId: teamId,
      sessionId: sessionId,
    );

    checkResultForMaintenance(ref, result);

    if (result.hasLeft) {
      _logger.e('Failed to fetch session: $sessionId', ex: result.left);
      throw result.left;
    }

    return result.right;
  }

  /// リソースリストを取得
  Future<PagingData<ResourceData>> _fetchResources() async {
    final result = await ref.read(repositoryProvider).getResourceDataList(
      teamId: teamId,
      sessionId: sessionId,
    );

    checkResultForMaintenance(ref, result);

    if (result.hasLeft) {
      _logger.e('Failed to fetch resources: $sessionId', ex: result.left);
      throw result.left;
    }

    return result.right;
  }

  /// AI コーチレポートを取得
  Future<AICoachReport?> _fetchReport(String reportId) async {
    final result = await ref.read(repositoryProvider).getAIReport(
      teamId: teamId,
      reportId: reportId,
    );

    checkResultForMaintenance(ref, result);

    if (result.hasLeft) {
      _logger.e('Failed to fetch AI coach report: $reportId', 
          ex: result.left);
      throw result.left;
    }

    return result.right;
  }

  /// 全てのデータをリフレッシュ
  /// 
  /// 使用例: Pull-to-refresh、レポート生成後など
  Future<void> refresh() async {
    _logger.d('Refreshing session details');

    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() => _fetchAllData());

    // 親の TeamList も無効化（セッション一覧の更新のため）
    ref.invalidate(teamListControllerProvider);
  }

  /// AI コーチレポートを生成
  /// 
  /// 成功時は自動的に refresh() を実行して新しいレポートを表示
  Future<void> generateReport() async {
    _logger.d('Generating AI coach report');

    try {
      final result = await ref.read(repositoryProvider).createAIReport(
        teamId: teamId,
        sessionId: sessionId,
      );

      checkResultForMaintenance(ref, result);

      if (result.hasLeft) {
        _logger.e('Failed to generate report', ex: result.left);
        throw result.left;
      }

      // レポート生成成功後、全データを再取得
      await refresh();

      _logger.i('Report generated successfully');
    } catch (e, stackTrace) {
      _logger.e('Error generating report', ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  /// AI コーチレポートを再生成
  /// 
  /// 既存のレポートを削除して新しく生成
  Future<void> regenerateReport() async {
    _logger.d('Regenerating AI coach report');

    final currentState = state.value;
    if (currentState == null) {
      _logger.w('Cannot regenerate report: state is null');
      return;
    }

    final reportId = currentState.session.aiCoachReport?.id;
    if (reportId == null) {
      _logger.w('Cannot regenerate report: no existing report');
      return;
    }

    try {
      // 既存レポートを削除
      final deleteResult = await ref.read(repositoryProvider).deleteAIReport(
        teamId: teamId,
        reportId: reportId,
      );

      if (deleteResult.hasLeft) {
        _logger.e('Failed to delete report', ex: deleteResult.left);
        throw deleteResult.left;
      }

      // 新しいレポートを生成
      await generateReport();

      _logger.i('Report regenerated successfully');
    } catch (e, stackTrace) {
      _logger.e('Error regenerating report', ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  /// リソースを削除
  /// 
  /// 削除後は自動的にリソースリストを更新
  Future<void> deleteResource(String resourceId) async {
    _logger.d('Deleting resource: $resourceId');

    try {
      final result = await ref.read(repositoryProvider).deleteResource(
        teamId: teamId,
        resourceId: resourceId,
      );

      checkResultForMaintenance(ref, result);

      if (result.hasLeft) {
        _logger.e('Failed to delete resource', ex: result.left);
        throw result.left;
      }

      // リソース削除後、全データを再取得
      await refresh();

      _logger.i('Resource deleted successfully');
    } catch (e, stackTrace) {
      _logger.e('Error deleting resource', ex: e, stacktrace: stackTrace);
      rethrow;
    }
  }

  /// セッション情報のみを更新
  /// 
  /// 例: セッション名変更後など、リソースやレポートは変わらない場合
  void updateSession(Session newSession) {
    final currentState = state.value;
    if (currentState == null) return;

    state = AsyncValue.data(
      currentState.copyWith(session: newSession),
    );
  }
}
```

