### 5. AI Coach Report Container の更新

```dart
// lib/views/pages/home/sessions/session_details/ai_coach_report/ai_coach_report_container.dart
class AICoachReportContainer extends HookConsumerWidget {
  const AICoachReportContainer({
    required this.session,
    required this.player,
    this.report,
    this.reportError,
    required this.onGenerateReport,
    required this.onRegenerateReport,
    super.key,
  });

  final Session session;
  final Player? player;
  final AICoachReport? report;  // ✅ AsyncValue ではなく直接値
  final String? reportError;
  final VoidCallback onGenerateReport;
  final VoidCallback onRegenerateReport;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // ✅ ローディング処理がシンプル
    if (report == null && session.aiCoachReport?.id != null && reportError == null) {
      return const Center(child: CustomLoadingIndicator());
    }

    // ✅ エラー処理がシンプル
    if (reportError != null) {
      return ReportGenerationStatusContent(
        player: player,
        title: context.l10n.ai_coach_report__generation_failed_title,
        description: context.l10n.ai_coach_report__generation_failed_description,
        buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
        onPressed: onGenerateReport,
      );
    }

    // ✅ レポートが存在しない場合
    if (report == null) {
      return EmptyContainer(
        player: player,
        session: session,
        onGenerateReport: onGenerateReport,
      );
    }

    // 以降は既存のロジック（status による分岐）
    final generationState = report.status;

    if (generationState == AICoachReportStatus.failed) {
      return ReportGenerationStatusContent(
        player: player,
        title: context.l10n.ai_coach_report__generation_failed_title,
        description: context.l10n.ai_coach_report__generation_failed_description,
        buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
        onPressed: onRegenerateReport,
      );
    }

    // ... 残りのロジック
  }
}
```

