// test/controllers/session_details_controller_test.dart
import 'package:flutter_test/flutter_test.dart';
import 'package:mockito/mockito.dart';
import 'package:riverpod/riverpod.dart';

void main() {
  group('SessionDetailsController', () {
    late ProviderContainer container;
    late MockRepository mockRepository;

    setUp(() {
      mockRepository = MockRepository();
      container = ProviderContainer(
        overrides: [
          repositoryProvider.overrideWithValue(mockRepository),
        ],
      );
    });

    tearDown(() {
      container.dispose();
    });

    test('初期状態で全てのデータを取得する', () async {
      // Arrange
      final mockSession = Session(id: 'session-1', teamId: 'team-1');
      final mockResources = PagingData<ResourceData>(items: []);

      when(mockRepository.getSession(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).thenAnswer((_) async => Right(mockSession));

      when(mockRepository.getResourceDataList(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).thenAnswer((_) async => Right(mockResources));

      // Act
      final state = await container.read(
        sessionDetailsControllerProvider(
          teamId: 'team-1',
          sessionId: 'session-1',
        ).future,
      );

      // Assert
      expect(state.session, mockSession);
      expect(state.resources, mockResources);
      expect(state.report, isNull);

      verify(mockRepository.getSession(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).called(1);

      verify(mockRepository.getResourceDataList(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).called(1);
    });

    test('レポート生成後、自動的にデータを再取得する', () async {
      // Arrange
      final mockSession = Session(
        id: 'session-1',
        teamId: 'team-1',
        aiCoachReport: AICoachReport(id: 'report-1'),
      );
      final mockResources = PagingData<ResourceData>(items: []);
      final mockReport = AICoachReport(
        id: 'report-1',
        status: AICoachReportStatus.completed,
      );

      when(mockRepository.createAIReport(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).thenAnswer((_) async => Right(mockReport));

      when(mockRepository.getSession(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).thenAnswer((_) async => Right(mockSession));

      when(mockRepository.getResourceDataList(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).thenAnswer((_) async => Right(mockResources));

      when(mockRepository.getAIReport(
        teamId: 'team-1',
        reportId: 'report-1',
      )).thenAnswer((_) async => Right(mockReport));

      // Act
      final controller = container.read(
        sessionDetailsControllerProvider(
          teamId: 'team-1',
          sessionId: 'session-1',
        ).notifier,
      );

      await controller.generateReport();

      // Assert
      final state = container.read(
        sessionDetailsControllerProvider(
          teamId: 'team-1',
          sessionId: 'session-1',
        ),
      ).value!;

      expect(state.report, mockReport);
      expect(state.session.aiCoachReport?.id, 'report-1');

      verify(mockRepository.createAIReport(
        teamId: 'team-1',
        sessionId: 'session-1',
      )).called(1);
    });
  });
}
