// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart' show Ball;
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/components/custom_dialog.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/all_balls_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/hooks/use_ai_report_generation.dart';

class RegenerateReportContent extends HookConsumerWidget {
  const RegenerateReportContent({
    required this.player,
    required this.currentSession,
    super.key,
  });

  final Player? player;
  final ValueNotifier<Session> currentSession;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final generateReport = useAIReportGeneration(
      player: player,
      currentSession: currentSession,
    );

    final sessionId = currentSession.value.id;
    final teamId = currentSession.value.teamId;

    if (sessionId == null || teamId == null) {
      return const SizedBox.shrink();
    }

    return AllBallsContainer(
      teamId: teamId,
      sessionId: sessionId,
      emptyWidget: SizedBox.shrink(),
      builder: ({
        required List<Ball> hittingBalls,
        required List<Ball> pitchingBalls,
      }) {
        return SizedBox(
          width: double.infinity,
          child: ElevatedButton(
            style: ButtonStyle(
              shape: WidgetStateProperty.all(
                RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(4),
                ),
              ),
            ),
            child: Padding(
              padding: const EdgeInsets.symmetric(vertical: 16.0),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  const Icon(Icons.auto_fix_high),
                  const Gap(8),
                  Text(context.l10n.ai_coach_report__regenerate_button_label),
                ],
              ),
            ),
            onPressed: () async {
              final shouldRegenerate = await showDialog<bool>(
                context: context,
                barrierDismissible: true,
                builder: (dialogContext) {
                  return CustomDialog.oneMessage(
                    title: dialogContext
                        .l10n.ai_coach_report__regenerate_button_label,
                    messageText: dialogContext
                        .l10n.ai_coach_report__regenerate_confirm_message,
                    aboveButtonText: dialogContext.l10n
                        .ai_coach_report__regenerate_confirm_above_button_label,
                    belowButtonText: dialogContext.l10n
                        .ai_coach_report__regenerate_confirm_below_button_label,
                    aboveButtonAction: (dialogActionContext) {
                      Navigator.of(dialogActionContext).pop(true);
                    },
                    belowButtonAction: (dialogActionContext) {
                      Navigator.of(dialogActionContext).pop(false);
                    },
                  );
                },
              );

              if (shouldRegenerate != true) {
                return;
              }

              await generateReport(
                hittingBalls: hittingBalls,
                pitchingBalls: pitchingBalls,
              );
            },
          ),
        );
      },
    );
  }
}

