import 'package:baseball_detector_flutter/views/pages/home/settings/settings_page.dart';
import 'package:baseball_detector_flutter/views/pages/notification_details/notification_details_page.dart';
import 'package:baseball_detector_flutter/views/pages/notification_list/notification_list_page.dart';
import 'package:baseball_detector_flutter/views/routers/navigation_streamer.dart';

enum HomeTabs {
  sessions,
  players,
  admin,
  settings,
}

class HomeRouter {
  HomeRouter._();

  static const String addSessionPage = '/addSessionPage';
  static const String adminPage = '/adminPage';
  static const String editProfilePage = '/editProfilePage';
  static const String editSessionPage = '/editSessionPage';
  static const String editTeamPage = '/editTeamPage';
  static const String editPlayerPage = '/editPlayerPage';
  static const String changePasswordPage = '/changePasswordPage';
  static const String changeUnits = '/changeUnits';
  static const String createPlayerPage = '/createPlayerPage';
  static const String playersPage = '/playersPage';
  static const String singleTeamPlayerPage = '/singleTeamPlayerPage';
  static const String resourceDetailPage = '/resourceDetailPage';
  static const String sessionDetailsPage = '/sessionDetailsPage';
  static const String sessionFilterPage = '/sessionFilterPage';
  static const String sessionsPage = '/';
  static const String settingsPage = '/settingsPage';
  static const String licensePage = '/licensePage';
  static const String licenseCheckerPage = '/licenseCheckerPage';
  static const String editMemberPage = '/editMemberPage';
  static const String inviteMemberPage = '/inviteMemberPage';
  static const String notificationListPage = '/notificationListPage';
  static const String notificationDetailsPage = '/notificationDetailsPage';

  static Widget getPage(BuildContext context, RouteSettings routeSettings) {
    switch (routeSettings.name) {
      case addSessionPage:
        return const AddSessionPage();
      case editProfilePage:
        return const EditProfilePage();
      case editSessionPage:
        final originalSession = routeSettings.arguments == null
            ? null
            : (routeSettings.arguments as Map<String, dynamic>)['session'];
        return EditSessionPage(originalSession: originalSession);
      case editTeamPage:
        return const EditTeamPage();
      case adminPage:
        return const AdminPage();
      case changePasswordPage:
        return const ChangePasswordPage();
      case changeUnits:
        return const ChangeUnitsPage();
      case licensePage:
        return const CustomLicensePage();
      case licenseCheckerPage:
        return const LicenseCheckerPage();
      case resourceDetailPage:
        final args = routeSettings.arguments as Map<String, dynamic>;
        final teamId = args['teamId'];
        final session = args['session'];
        final resourceId = args['resourceId'];
        return ResourceDetailsPage(
          teamId: teamId,
          session: session,
          resourceId: resourceId,
        );
      case playersPage:
        return const PlayersPage();
      case singleTeamPlayerPage:
        return SingleTeamPlayerPage();
      case sessionDetailsPage:
        final args = routeSettings.arguments as Map<String, dynamic>;
        final teamId = args['teamId'];
        final sessionId = args['sessionId'];
        final session = args['session'];
        return SessionDetailsPage(
          teamId: teamId,
          sessionId: sessionId,
          session: session,
        );
      case sessionFilterPage:
        return const SessionFilterPage();
      case sessionsPage:
        return const SessionsPage();
      case settingsPage:
        return const SettingsPage();
      case editPlayerPage:
        final player = (routeSettings.arguments
            as Map<String, dynamic>)['player'] as Player;
        return EditPlayerPage(player: player);
      case createPlayerPage:
        return const CreatePlayerPage();
      case editMemberPage:
        final member =
            (routeSettings.arguments as Map<String, dynamic>)['member'];
        return EditMemberPage(member: member);
      case inviteMemberPage:
        return const InviteMemberPage();
      case notificationListPage:
        return const NotificationListPage();
      case notificationDetailsPage:
        final args = routeSettings.arguments as Map<String, dynamic>;
        final notification = args['notification'];
        return NotificationDetailsPage(notification: notification);
      default:
        throw 'Undefined route "${routeSettings.name}" found.';
    }
  }

  static HomeTabs getTab(String path) {
    switch (path) {
      case sessionsPage:
      case sessionFilterPage:
      case sessionDetailsPage:
      case editSessionPage:
      case addSessionPage:
      case resourceDetailPage:
        return HomeTabs.sessions;
      case playersPage:
      case editPlayerPage:
      case createPlayerPage:
      case singleTeamPlayerPage:
        return HomeTabs.players;
      case adminPage:
      case editTeamPage:
      case editMemberPage:
      case inviteMemberPage:
        return HomeTabs.admin;
      case settingsPage:
      case editProfilePage:
      case changePasswordPage:
      case changeUnits:
      case licensePage:
      case licenseCheckerPage:
      case notificationListPage:
      case notificationDetailsPage:
        return HomeTabs.settings;
      default:
        throw 'Undefined path "$path" found.';
    }
  }
}

